const collectionHolder=document.querySelector("[data-collection-holder]");const addButton=document.getElementById("add-text-btn");let index=collectionHolder.querySelectorAll(".collection-item").length;addButton.addEventListener("click",(()=>{const prototype=collectionHolder.dataset.prototype;const newForm=prototype.replace(/__name__/g,index);const wrapper=document.createElement("div");wrapper.className="collection-item";wrapper.innerHTML=newForm;collectionHolder.appendChild(wrapper);index++}));document.addEventListener("click",(function(e){if(e.target&&e.target.classList.contains("remove-text")){e.preventDefault();const collectionItem=e.target.closest(".collection-item");if(collectionItem){collectionItem.remove()}}}));let $blockImage=document.getElementById("image_wrapper");["dragenter","dragover","dragleave","drop"].forEach((event=>{$blockImage.addEventListener(event,(function(e){e.preventDefault();e.stopPropagation()}),false)}));["dragenter","dragover"].forEach((event=>{$blockImage.addEventListener(event,(()=>{$blockImage.classList.add("shadow")}),false)}));["dragleave","drop"].forEach((event=>{$blockImage.addEventListener(event,(()=>{$blockImage.classList.remove("shadow")}),false)}));$blockImage.addEventListener("drop",(function(e){const dt=e.dataTransfer;const files=dt.files;[...files].forEach(previewAndAttachFile)}));function previewAndAttachFile(file){if(!file.type.startsWith("image/")){return}const reader=new FileReader;reader.readAsDataURL(file);reader.onloadend=function(){$blockImage.querySelector("label").style.backgroundImage=`url('${reader.result}')`;const fileInput=$blockImage.querySelector('input[type="file"]');const dataTransfer=new DataTransfer;dataTransfer.items.add(file);fileInput.files=dataTransfer.files}}